{
  "error": "missing_brave_api_key",
  "message": "web_search (brave) needs a Brave Search API key. Run `openclaw configure --section web` to store it, or set BRAVE_API_KEY in the Gateway environment.",
  "docs": "https://docs.openclaw.ai/tools/web"
}

const BASE='https://services.leadconnectorhq.com';
const TOKEN=process.env.GHL_PRIVATE_INTEGRATION_TOKEN_TJB||process.env.GHL_PRIVATE_INTEGRATION_TOKEN;
const LOCATION='TW8JsPW5NMnA3tfK2XLn';
if(!TOKEN){console.log(JSON.stringify({error:'missing_token'}));process.exit(0)}
const headers={Authorization:`Bearer ${TOKEN}`,Version:'2021-07-28',Accept:'application/json'};
const DAY=24*60*60*1000; const now=Date.now(); const cutoff=now-DAY;
const toArr=x=>Array.isArray(x)?x:[];
const toMs=v=>{if(v==null) return 0; const n=Number(v); if(Number.isFinite(n)&&n>0) return n<1e12?n*1000:n; const d=Date.parse(v); return Number.isFinite(d)?d:0};
const norm=s=>String(s||'').trim().toLowerCase().replace(/\s+/g,' ');
async function req(path){const r=await fetch(BASE+path,{headers}); const t=await r.text(); let j={}; try{j=t?JSON.parse(t):{}}catch{j={raw:t}}; return {ok:r.ok,status:r.status,body:j};}
async function getConvs(){let p=1,out=[]; while(p<=20){const r=await req(`/conversations/search?locationId=${LOCATION}&limit=100&page=${p}`); if(!r.ok) break; const a=toArr(r.body.conversations||r.body.data?.conversations||r.body.data); out.push(...a); if(a.length<100) break; p++;} return out;}
(async()=>{
const convs=await getConvs();
const active=convs.filter(c=>Math.max(toMs(c.lastMessageDate),toMs(c.dateUpdated),toMs(c.dateAdded))>=cutoff);
const negRx=/\b(stop|unsubscribe|opt\s*out|remove me|dont text|don't text|leave me alone|cancel|not interested|wrong number|spam|complaint|report)\b/i;
const complaintRx=/\b(spam|complaint|report(ed)?\s+as\s+spam|harass|lawsuit|attorney|fcc|ftc)\b/i;
let outbound=0,hardFail=0,optOut=0,complaint=0,negative=0,dup=0;
const seen=new Map();
for(const c of active){
  const mr=await req(`/conversations/${c.id}/messages?limit=200`);
  if(!mr.ok) continue;
  const msgs=toArr(mr.body.messages?.messages||mr.body.messages||mr.body.data?.messages||mr.body.data).sort((a,b)=>toMs(a.dateAdded)-toMs(b.dateAdded));
  const recent=msgs.filter(m=>toMs(m.dateAdded)>=cutoff);
  for(const m of recent){
    const dir=String(m.direction||'').toLowerCase();
    const body=String(m.body||'');
    const type=String(m.messageType||'');
    if(dir==='outbound'){
      if(type.includes('TYPE_ACTIVITY')||type.includes('TYPE_CALL')||type.includes('TYPE_PAYMENT')||type.includes('TYPE_NOTE')) continue;
      outbound++;
      const st=String(m.status||'').toLowerCase();
      if(/failed|undeliver|bounce|rejected|error|blocked|invalid/.test(st)) hardFail++;
      const key=`${m.contactId||c.contactId}|${norm(body)}|${String(m.messageType||'')}`;
      const t=toMs(m.dateAdded);
      const prev=seen.get(key);
      if(prev && (t-prev)<=5*60*1000) dup++;
      seen.set(key,t);
    } else if(dir==='inbound'){
      if(negRx.test(body)) negative++;
      if(/\b(stop|unsubscribe|opt\s*out|remove me|dont text|don't text|cancel|wrong number)\b/i.test(body)) optOut++;
      if(complaintRx.test(body)) complaint++;
    }
  }
}
const rate=(n,d)=>d?+(100*n/d).toFixed(2):0;
const out={
  sample:{conversations_scanned:active.length,outbound_messages_24h:outbound},
  metrics:{
    opt_out_rate_pct:rate(optOut,outbound),
    complaint_rate_pct:rate(complaint,outbound),
    reply_negative_rate_pct:rate(negative,outbound),
    duplicate_send_rate_pct:rate(dup,outbound),
    hard_fail_rate_pct:rate(hardFail,outbound)
  },
  counts:{optOut,complaint,negative,dup,hardFail}
};
console.log(JSON.stringify(out,null,2));
})();
